def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        weight = 1.0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    val = ((ratio - a) ** 6) / ((a + b) * 1.1 + 1)
                    val *= np.sin(ratio * b / (a + 1)) + np.cos(ratio * a / (b + 1))
                    priority += val * np.power(-1, a + b)
            priority += (np.exp(ratio - 7) * np.cos(ratio * 1.3)) ** 1.7
            if bin_cap < item * 0.5:
                priority += np.sqrt(item * bin_cap) * 3.7
            else:
                priority -= np.exp(-ratio) * 5.5
        elif 4 < ratio <= 7:
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 3):
                    term = ((ratio - p) ** 4) * np.cos(ratio * q) / (q + 0.7)
                    priority += np.tanh(term) * 1.4
            priority += np.log(ratio) * 12 - np.tanh(ratio - 4) * 3
            if bin_cap > item * 2:
                priority -= np.log1p(bin_cap / item) * 2
            else:
                priority += np.sqrt(bin_cap * item) * 1.4
        elif 2 <= ratio <= 4:
            s = 0
            for r in range(1, 15):
                val = ((ratio - 2) ** r) / (r * 2.1) * np.sin(r * ratio * 1.1)
                if r % 2 == 0:
                    val *= np.cos(ratio)
                else:
                    val *= np.sin(ratio)
                s += val
            priority = (s * np.sin(6 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (4 - ratio)) * 2
            if bin_cap < item * 0.8:
                priority += np.sin(ratio * i * 2) * 4
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * np.cos(n * ratio * 1.5)
            penalty = np.sqrt(item / (bin_cap + 1))
            if bin_cap < item * 1.05:
                penalty *= 5
            else:
                penalty *= np.cos(15 * ratio) * 3
            priority = s + penalty + np.exp(-1.8 / (ratio + 0.03))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i) * ((ratio - 1) ** m) / (m + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 20):
                s += ((1 - ratio) ** n) / (n * 3.5) * np.sin(n * item * 1.3)
            priority = s
            if (i + int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.cos(j * item * 1.4) * 0.9
            if bin_cap < item * 0.7:
                priority += np.log1p(item * bin_cap) * 6
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 15):
                s += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 3)
            priority = s + 2 / (bin_cap + 5)
            if int(item * 1.5) % 6 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.exp(-item / (bin_cap + 1)) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 10):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.sin(item * m * 0.9)
        else:
            s = 0
            for t in range(1, 15):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.6) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 9) * np.cos(item * u * 0.7)
        if bin_cap < item * 0.4:
            priority += np.log1p(item ** 2 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.5
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.5
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        if ratio > 5 and bin_cap < item * 1.5:
            for z in range(1, 5):
                priority += np.sin(z * ratio * i) * np.exp(-z / (ratio + 0.1)) * 2.5
        elif 2 < ratio <= 5:
            for w in range(3, 8):
                val = ((ratio - 2) ** w) / (w * 2) * np.cos(w * ratio * 1.4)
                if (i + w) % 2 == 0:
                    val *= 1.3
                else:
                    val *= 0.7
                priority += val
        else:
            if ratio < 0.4 and bin_cap > item:
                penalty = np.tanh(ratio * bin_cap / (item + 0.1)) * 3
                priority -= penalty
            else:
                bonus = np.log1p(bin_cap + ratio * item) * 1.2
                priority += bonus
        priorities[i] = priority * weight
    return priorities
